import{_ as a,o,c as n,j as e,a as r}from"./chunks/framework.DH-ORP1j.js";const _=JSON.parse('{"title":"甲午中日战争：1894-1895，侵略势","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-19.md","filePath":"notes/note-19.md"}'),s={name:"notes/note-19.md"};function c(d,t,l,i,p,m){return o(),n("div",null,[...t[0]||(t[0]=[e("h1",{id:"甲午中日战争-1894-1895-侵略势",tabindex:"-1"},[r("甲午中日战争：1894-1895，侵略势 "),e("a",{class:"header-anchor",href:"#甲午中日战争-1894-1895-侵略势","aria-label":'Permalink to "甲午中日战争：1894-1895，侵略势"'},"​")],-1),e("p",null,"甲午中日战争：1894-1895，侵略势力进一步深入中国腹地，大大加深了中国半殖民地化程度，刺激列强掀起瓜分中国狂潮，进一步加剧民族危机。激起中华民族觉醒，推动中国人民展开救亡图存斗争（百日维新、实业救国） 《马关条约》：割三地（辽东半岛、澎湖列岛、台湾）赔两亿（白银）开四口（沙市、重庆、苏州、杭州）允设厂（日本在通商口岸开设工厂）。 《辛丑》：①清政府赔款白银4.5亿两，分39年还清，本息共计9. 8亿两，以海关税、盐税等税收作担保;②清政府保证严禁人民参加各种形式的反帝活动;清政府拆毁大沽炮台，③允许外国军队驻扎在从北京到山海关的铁路沿线要地;④划定北京东交民巷为使馆界，允许各国派兵驻守，不准中国人居住，改总理衙门为外务部，班列六部之前。 《辛丑》影响：清政府沦为帝国主义列统治中国的工具，中国完全陷入半殖民地半封建社会的深渊。 1、第一次近代化运动:洋务运动（近代化的开端） 中国近代史的开端：鸦片战争 2、洋务运动破产的标志：甲午战争北洋舰队全军覆没 3、拉开维新变法运动的序幕是：公车上书 4、义和团的口号、性质：扶清灭洋、广泛群众性反帝爱国运动 5、沦为洋人朝廷是哪个条约：《辛丑条约》 6、客观上促进中国民族资本主义产生是哪件事？洋务运动 7、李鸿章办的军事工业：江南机器制造总局（封建性质） 8、梁启超在（上海）办了《时务报》报刊。严复（天津）办了《国闻报》。 9、政治近代化的开端是：百日维新 10、沉重打击帝国主义瓜分中国野心是哪件事？义和团运动 11、教育近代化的开端是哪件事？洋务运动（京师同文馆） 1、第一次鸦片战争的时间：1840-1842年 导火线：林则徐虎门销烟 3、第二次鸦片战争的根本原因：西方列强为打开中国市场，倾销商品，掠夺原材料 4、第一次鸦片战争失败根因：清朝封建专制制度的腐败 6、近代侵占我国领土最多的国家是：俄国 7、天平天国运动军事上全盛：北伐、西征 8、西方侵略势力由东南沿海深入到长江中下游地区是哪场战争？第二次鸦片战争（《天津》外国商船和军舰可在长江各口岸自由航行。",-1)])])}const h=a(s,[["render",c]]);export{_ as __pageData,h as default};
